void	abc_error(char *fmt, ...)
{
	va_list	ap;
	va_start(ap,fmt);
	(void) fprintf(stderr,"error in input file %s: line no. %d - ",
				abc_file,input_line);
	(void) vfprintf(stderr,fmt,ap);
	(void) fprintf(stderr,"\n");
	va_end(ap);
	exit(1);
}

RELEVANT TYPE DEFINITIONS (RECURSIVE):


CALLED EXTERNAL FUNCTIONS:
exit, fprintf, vfprintf, __builtin_va_end, __builtin_va_start
</c_context>

<unsafe_rust_function>
#[no_mangle]
pub unsafe extern "C" fn abc_error(mut fmt: *mut core::ffi::c_char, mut args: ...) {
    let mut ap: ::core::ffi::VaListImpl;
    ap = args.clone();
    fprintf(
        stderr,
        b"error in input file %s: line no. %d - \0" as *const u8
            as *const core::ffi::c_char,
        abc_file.as_mut_ptr(),
        input_line,
    );
    vfprintf(stderr, fmt, ap.as_va_list());
    fprintf(stderr, b"\n\0" as *const u8 as *const core::ffi::c_char);
    exit(1 as core::ffi::c_int);
}
</unsafe_rust_function>

