#[no_mangle]
pub unsafe extern "C" fn open_TeX(
    mut s: *mut core::ffi::c_char,
    mut musix_out: core::ffi::c_int,
) {
    if *s.offset(0 as core::ffi::c_int as isize) as core::ffi::c_int == '\0' as i32 {
        Out = fopen(
            b"music.tex\0" as *const u8 as *const core::ffi::c_char,
            b"w\0" as *const u8 as *const core::ffi::c_char,
        ) as *mut FILE;
    } else {
        Out = fopen(s, b"w\0" as *const u8 as *const core::ffi::c_char) as *mut FILE;
    }
    musix = musix_out;
    if musix != 0 {
        fprintf(Out, b"\\def\\abcmusix{Y}\n\0" as *const u8 as *const core::ffi::c_char);
        if musix == 1 as core::ffi::c_int {
            fprintf(
                Out,
                b"\\def\\abcopus{N}\n\0" as *const u8 as *const core::ffi::c_char,
            );
        }
        if musix == 2 as core::ffi::c_int {
            fprintf(
                Out,
                b"\\def\\abcopus{Y}\n\0" as *const u8 as *const core::ffi::c_char,
            );
        }
    } else {
        fprintf(Out, b"\\def\\abcmusix{N}\n\0" as *const u8 as *const core::ffi::c_char);
    }
    if settings.mine != 0 {
        fprintf(Out, b"\\input dscgrphy\n\0" as *const u8 as *const core::ffi::c_char);
    }
    fprintf(Out, b"\\input header\n%%\n\0" as *const u8 as *const core::ffi::c_char);
    if musix == 1 as core::ffi::c_int {
        fprintf(Out, b"\\startmuflex%%\n\0" as *const u8 as *const core::ffi::c_char);
    }
}
